+  it("preserves explicit mode and dryRun values", () => {
+    const logger = { warn: (_message: string) => {} };
+    const result = resolveInstallModeOptions(
+      {
+        logger,
+        mode: "update",
+        dryRun: true,
+      },
+      { warn: () => {} },
+    );
+
+    expect(result).toEqual({
+      logger,
+      mode: "update",
+      dryRun: true,
+    });
+  });
+
+  it("uses default timeout when not provided", () => {
+    const logger = { warn: (_message: string) => {} };
